import{_ as d,o as e,c as o,ak as c}from"./chunks/framework.D56sOg_b.js";const p=JSON.parse('{"title":"Lambda 使用指南","description":"","frontmatter":{"version":"2.0.0"},"headers":[],"relativePath":"java/lambda.md","filePath":"java/lambda.md","lastUpdated":1777342039000}'),a={name:"java/lambda.md"};function r(n,t,l,i,g,b){return e(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="lambda-使用指南" tabindex="-1">Lambda 使用指南 <a class="header-anchor" href="#lambda-使用指南" aria-label="Permalink to “Lambda 使用指南”">​</a></h1><p><code>Lambda</code> 表达式是 Java 8 引入的语法特性，用于以更简洁的方式表示函数式接口的实现。它本质上是一种匿名函数写法，常用于替代匿名内部类。</p><h2 id="命令式和函数式" tabindex="-1">命令式和函数式 <a class="header-anchor" href="#命令式和函数式" aria-label="Permalink to “命令式和函数式”">​</a></h2><ul><li>命令式编程：关注“如何实现（how）”，明确给出执行步骤。</li><li>声明式编程：关注“要得到什么（what）”，由框架或运行时决定具体执行方式。</li></ul><h2 id="什么是函数式编程" tabindex="-1">什么是函数式编程？ <a class="header-anchor" href="#什么是函数式编程" aria-label="Permalink to “什么是函数式编程？”">​</a></h2><p>函数式编程强调通过函数组合、不可变数据和表达式求值完成计算过程。</p><h2 id="函数描述符" tabindex="-1">函数描述符 <a class="header-anchor" href="#函数描述符" aria-label="Permalink to “函数描述符”">​</a></h2><p>函数式接口中抽象方法的签名可以用于描述 <code>Lambda</code> 表达式的参数和返回值形式，该签名称为函数描述符。</p><h2 id="函数式接口-类型推断" tabindex="-1">函数式接口，类型推断 <a class="header-anchor" href="#函数式接口-类型推断" aria-label="Permalink to “函数式接口，类型推断”">​</a></h2><p>函数式接口有且仅有一个抽象方法。编译器可根据上下文对 <code>Lambda</code> 表达式进行类型推断，因此通常不需要显式声明完整类型信息。</p><h2 id="java-8-中的常用函数式接口" tabindex="-1">Java 8 中的常用函数式接口 <a class="header-anchor" href="#java-8-中的常用函数式接口" aria-label="Permalink to “Java 8 中的常用函数式接口”">​</a></h2><table tabindex="0"><thead><tr><th>函数式接口</th><th>函数描述符</th><th>原始类型特化</th></tr></thead><tbody><tr><td><code>Predicate&lt;T&gt;</code></td><td><code>T-&gt;boolean</code></td><td><code>IntPredicate</code> <code>LongPredicate</code> <code>DoublePredicate</code></td></tr><tr><td><code>Consumer&lt;T&gt;</code></td><td><code>T-&gt;void</code></td><td><code>IntConsumer</code> <code>LongConsumer</code> <code>DoubleConsumer</code></td></tr><tr><td><code>Function&lt;T,R&gt;</code></td><td><code>T-&gt;R</code></td><td><code>IntFunction&lt;R&gt;</code> <code>IntToDoubleFunction</code> <code>IntToLongFunction</code> <code>LongFunction&lt;R&gt;</code> <code>LongToDoubleFunction</code> <code>LongToIntFunction</code> <code>DoubleFunction&lt;R&gt;</code> <code>ToIntFunction&lt;T&gt;</code> <code>ToDoubleFunction&lt;T&gt;</code> <code>ToLongFunction&lt;T&gt;</code></td></tr><tr><td><code>Supplier&lt;T&gt;</code></td><td><code>()-&gt;T</code></td><td><code>BooleanSupplier</code> <code>IntSupplier</code> <code>LongSupplier</code> <code>DoubleSupplier</code></td></tr><tr><td><code>UnaryOperator&lt;T&gt;</code></td><td><code>T-&gt;T</code></td><td><code>IntUnaryOperator</code> <code>LongUnaryOperator</code> <code>DoubleUnaryOperator</code></td></tr><tr><td><code>BinaryOperator&lt;T&gt;</code></td><td><code>(T,T)-&gt;T</code></td><td><code>IntBinaryOperator</code> <code>LongBinaryOperator</code> <code>DoubleBinaryOperator</code></td></tr><tr><td><code>BiPredicate&lt;L,R&gt;</code></td><td><code>(L,R)-&gt;boolean</code></td><td></td></tr><tr><td><code>BiConsumer&lt;T,U&gt;</code></td><td><code>(T,U)-&gt;void</code></td><td><code>ObjIntConsumer&lt;T&gt;</code> <code>ObjLongConsumer&lt;T&gt;</code> <code>ObjDoubleConsumer&lt;T&gt;</code></td></tr><tr><td><code>BiFunction&lt;T,U,R&gt;</code></td><td><code>(T,U)-&gt;R</code></td><td><code>ToIntBiFunction&lt;T,U&gt;</code> <code>ToLongBiFunction&lt;T,U&gt;</code> <code>ToDoubleBiFunction&lt;T,U&gt;</code></td></tr></tbody></table><h2 id="lambda-与函数式接口示例" tabindex="-1">Lambda 与函数式接口示例 <a class="header-anchor" href="#lambda-与函数式接口示例" aria-label="Permalink to “Lambda 与函数式接口示例”">​</a></h2><table tabindex="0"><thead><tr><th>使用示例</th><th>Lambda 的例子</th><th>对应的函数式接口</th></tr></thead><tbody><tr><td>布尔表达式</td><td><code>(List&lt;String&gt; list) -&gt; list.isEmpty()</code></td><td><code>Predicate&lt;List&lt;String&gt;&gt;</code></td></tr><tr><td>创建对象</td><td><code>() -&gt; new Project()</code></td><td><code>Supplier&lt;Project&gt;</code></td></tr><tr><td>消费一个对象</td><td><code>(Project p) -&gt; System.out.println(p.getStars())</code></td><td><code>Consumer&lt;Project&gt;</code></td></tr><tr><td>从一个对象中选择/提取</td><td><code>(int a, int b) -&gt; a * b</code></td><td><code>IntBinaryOperator</code></td></tr><tr><td>比较两个对象</td><td><code>(Project p1, Project p2) -&gt; p1.getStars().compareTo(p2.getStars())</code></td><td><code>Comparator&lt;Project&gt;</code> <code>BiFunction&lt;Project,Project, Integer&gt;</code> <code>ToIntBiFunction&lt;Project, Project&gt;</code></td></tr></tbody></table>',14)])])}const s=d(a,[["render",r]]);export{p as __pageData,s as default};
